using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e6+5;
int n,m,trie[30][MAXN],cnt[MAXN],ed[MAXN],idx=1; 
void insert(string s)
{
	int len=s.size()-1,o=1;
	FOR(i,0,len)
	{
		if(trie[s[i]-'a'][o]==0)
		{
			trie[s[i]-'a'][o]=++idx;
		}
		o=trie[s[i]-'a'][o];
		++cnt[o]; 
	} 
	++ed[o];
	return;
}
int find(string s)
{
	int len=s.size()-1,o=1,ans=0;
	FOR(i,0,len)
	{
		if(trie[s[i]-'a'][o]==0)return ans;
		o=trie[s[i]-'a'][o];
		ans+=ed[o];
	} 
	return ans;
}
signed main(void)
{
    // freopen("in.txt","r",stdin);
